  "lessonText": "Master the basics of cooking to build your culinary confidence.",
  "data": {
    "learningCards": [
      {
        "title": "Essential Kitchen Tools",
        "content": "Know your tools: \n- Knife: for chopping and slicing. \n- Cutting board: for food prep. \n- Pots and pans: for cooking. \n- Measuring cups: for accuracy.",
        "layout": "simple"
      },
      {
        "title": "Basic Cooking Techniques",
        "content": "Learn fundamental techniques: \n- Boiling: cooking in water. \n- Sautéing: cooking in a little oil. \n- Baking: using the oven. \n- Grilling: cooking over heat.",
        "layout": "simple"
      },
      {
        "title": "Understanding Ingredients",
        "content": "Familiarize yourself with ingredients: \n- Fresh vs. dried herbs. \n- Types of oils: olive, vegetable. \n- Seasoning basics: salt, pepper. \n- Protein sources: meat, beans.",
        "layout": "simple"
      },
      {
        "title": "Safety in the Kitchen",
        "content": "Prioritize safety: \n- Keep knives sharp. \n- Clean as you go. \n- Avoid cross-contamination. \n- Be aware of hot surfaces.",
        "layout": "simple"
      }
    ]
  }
}
